@namespace Lumeo

@{
    var context = new PopoverContext(Open, EventCallback.Factory.Create<bool>(this, SetOpen), _wrapperId, _contentId);
}

<CascadingValue Value="context" IsFixed="false">
    @* tabindex=-1 makes the wrapper a programmatic focus target so PopoverContent
       can return focus here on close (the trigger lives inside it). *@
    <div id="@_wrapperId" class="relative inline-block outline-none" tabindex="-1" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
</CascadingValue>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool Open { get; set; }
    [Parameter] public EventCallback<bool> OpenChanged { get; set; }

    [Obsolete("Use Open instead. IsOpen will be removed in a future release.")]
    [Parameter] public bool IsOpen { get => Open; set => Open = value; }

    [Obsolete("Use OpenChanged instead. IsOpenChanged will be removed in a future release.")]
    [Parameter] public EventCallback<bool> IsOpenChanged { get => OpenChanged; set => OpenChanged = value; }

    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _wrapperId = LumeoIds.New("popover");
    // Stable content id shared with the trigger (aria-controls) and the content
    // (focus management / role=dialog target) so the trigger can advertise the
    // relationship and the content can focus itself on open.
    internal readonly string _contentId = LumeoIds.New("popover-content");

    private async Task SetOpen(bool value)
    {
        Open = value;
        await OpenChanged.InvokeAsync(value);
    }

    public record PopoverContext(bool IsOpen, EventCallback<bool> SetOpen, string WrapperId, string ContentId);
}

@namespace Lumeo
@implements IAsyncDisposable

@if (Context.IsOpen)
{
    <div id="@_contentId" role="dialog" class="@CssClass" @onkeydown="HandleKeyDown" tabindex="-1" @attributes="AdditionalAttributes">
        @ChildContent
        @if (ShowArrow)
        {
            <div class="@ArrowClasses"></div>
        }
    </div>
}

@inject IComponentInteropService Interop

@code {
    [CascadingParameter] public Popover.PopoverContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public Lumeo.Align Align { get; set; } = Lumeo.Align.Center;
    [Parameter] public Lumeo.Side Side { get; set; } = Lumeo.Side.Bottom;
    [Parameter] public bool ShowArrow { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Use the content id provided by the Popover parent so the trigger's
    // aria-controls points at this element and focus management can target it.
    private string _contentId => Context.ContentId;
    private bool _registered;

    private string CssClass => Cx.Merge(
        "fixed z-50 w-72 rounded-md border border-border/60 bg-popover p-4 text-popover-foreground shadow-lg outline-none",
        ShowArrow ? "overflow-visible" : "overflow-hidden",
        "animate-fade-in",
        Class);

    private string AlignStr => Align switch
    {
        Lumeo.Align.Start => "start",
        Lumeo.Align.Center => "center",
        Lumeo.Align.End => "end",
        _ => "center"
    };

    private string SideStr => Side switch
    {
        Lumeo.Side.Top => "top",
        Lumeo.Side.Left => "left",
        Lumeo.Side.Right => "right",
        _ => "bottom"
    };

    // Rotated square so the arrow inherits both the popover surface colour AND a matching border
    // on the two sides that face out — looks sharper than the hollow-triangle trick and lines the
    // arrow up with the popover corner radius visually.
    private string ArrowClasses => Side switch
    {
        Lumeo.Side.Top => "absolute left-1/2 top-full -translate-x-1/2 -translate-y-1/2 rotate-45 h-2.5 w-2.5 bg-popover border-b border-r border-border/60",
        Lumeo.Side.Bottom => "absolute left-1/2 bottom-full -translate-x-1/2 translate-y-1/2 rotate-45 h-2.5 w-2.5 bg-popover border-t border-l border-border/60",
        Lumeo.Side.Left => "absolute top-1/2 left-full -translate-y-1/2 -translate-x-1/2 rotate-45 h-2.5 w-2.5 bg-popover border-t border-r border-border/60",
        Lumeo.Side.Right => "absolute top-1/2 right-full -translate-y-1/2 translate-x-1/2 rotate-45 h-2.5 w-2.5 bg-popover border-b border-l border-border/60",
        _ => "absolute left-1/2 bottom-full -translate-x-1/2 translate-y-1/2 rotate-45 h-2.5 w-2.5 bg-popover border-t border-l border-border/60"
    };

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (Context.IsOpen && !_registered)
        {
            await Interop.PositionFixed(_contentId, Context.WrapperId, AlignStr, false, SideStr);
            await Interop.RegisterClickOutside(_contentId, Context.WrapperId, async () =>
            {
                await Context.SetOpen.InvokeAsync(false);
                await InvokeAsync(StateHasChanged);
            });
            _registered = true;

            // Move focus into the dialog content on open. Without this, focus
            // stays on the trigger and the content's @onkeydown handler never
            // receives Escape (Radix-equivalent dialog popovers manage focus).
            try { await Interop.FocusElement(_contentId); } catch (JSDisconnectedException) { }
        }
        else if (!Context.IsOpen && _registered)
        {
            await Cleanup();
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Escape") await Context.SetOpen.InvokeAsync(false);
    }

    private async Task Cleanup()
    {
        try { await Interop.UnpositionFixed(_contentId); } catch (JSDisconnectedException) { }
        try { await Interop.UnregisterClickOutside(_contentId); } catch (JSDisconnectedException) { }
        // Return focus to the trigger region on close so keyboard users aren't
        // dropped back to the document body.
        try { await Interop.FocusElement(Context.WrapperId); } catch (JSDisconnectedException) { }
        _registered = false;
    }

    public async ValueTask DisposeAsync()
    {
        if (_registered) await Cleanup();
    }

}

@namespace Lumeo

@if (AsChild)
{
    @* asChild: render NO wrapper. Cascade the slot so a cooperating child (a Lumeo
       <Button>, or a manual <ChildContentSlot> splat) becomes the single trigger
       element — no role=button div, no nested-interactive markup, and the child's
       own Class/width reach the real control. Popover positions against the Popover
       ROOT wrapper (Context.WrapperId), not this trigger, so dropping the wrapper
       does not affect positioning — no id transfer needed. *@
    <CascadingValue Value="Slot" IsFixed="false">
        @if (ChildContentSlot is not null)
        {
            @ChildContentSlot(Slot)
        }
        else
        {
            @ChildContent
        }
    </CascadingValue>
}
else
{
    <div class="@CssClass" role="button" tabindex="0" aria-expanded="@(Context.IsOpen ? "true" : "false")" aria-haspopup="dialog" aria-controls="@(Context.IsOpen ? Context.ContentId : null)" @onclick="Toggle" @onkeydown="HandleKeyDown" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
}

@code {
    [CascadingParameter] public Popover.PopoverContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>
    /// Tier-2 escape hatch for <see cref="AsChild"/> with arbitrary (non-Lumeo) markup:
    /// receives the <see cref="TriggerSlot"/> so the consumer can splat
    /// <c>@attributes="slot.Attributes"</c> and wire <c>@onclick="slot.OnClick.InvokeAsync"</c>
    /// onto their own single element. Lumeo <c>&lt;Button&gt;</c> children need only
    /// <see cref="AsChild"/> — they consume the slot automatically.
    /// </summary>
    [Parameter] public RenderFragment<TriggerSlot>? ChildContentSlot { get; set; }

    /// <summary>
    /// When <c>true</c>, the trigger renders NO wrapper element and instead cascades a
    /// <see cref="TriggerSlot"/> that a cooperating child folds onto its own single root
    /// element — yielding ONE DOM node with merged class, composed click/keyboard, and
    /// forwarded ARIA/state (the Radix <c>asChild</c> goal). The child must resolve to
    /// exactly one cooperating element (a Lumeo <c>&lt;Button&gt;</c>, or a manual
    /// <see cref="ChildContentSlot"/> splat); raw HTML/3rd-party markup receives nothing.
    /// Default <c>false</c> preserves the current <c>role=button</c> wrapper exactly.
    ///
    /// Prefer a <c>&lt;button&gt;</c> child for a click-toggle trigger: a
    /// <c>&lt;Button Href&gt;</c> renders an <c>&lt;a&gt;</c>, which natively activates
    /// on Enter only (not Space), so Space would not open the popover.
    /// </summary>
    [Parameter] public bool AsChild { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("inline-flex", Class);

    private TriggerSlot Slot => new(
        Id: null,                                 // Popover anchors positioning on its root wrapper, not the trigger
        Class: Cx.Merge("inline-flex", Class),
        Attributes: BuildAttrs(),
        OnClick: EventCallback.Factory.Create<MouseEventArgs>(this, _ => Toggle()),
        OnKeyDown: EventCallback.Factory.Create<KeyboardEventArgs>(this, HandleKeyDown));

    private IReadOnlyDictionary<string, object> BuildAttrs()
    {
        var d = new Dictionary<string, object>
        {
            ["aria-haspopup"] = "dialog",
            ["aria-expanded"] = Context.IsOpen ? "true" : "false",
        };
        if (Context.IsOpen) d["aria-controls"] = Context.ContentId;
        if (AdditionalAttributes is not null)
            foreach (var kv in AdditionalAttributes) d[kv.Key] = kv.Value; // author wins on collision
        return d;
    }

    private async Task Toggle() => await Context.SetOpen.InvokeAsync(!Context.IsOpen);

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key is "Enter" or " ") await Toggle();
    }
}
